import React, { useState } from "react";
import UploadCV from "./components/UploadCV";
import Result from "./components/Result";
import "./App.css";

function App() {
    const [result, setResult] = useState(null);
    const [loading, setLoading] = useState(false);

    return (
        <div className="app">
            {/* Background decorations */}
            <div className="bg-orb orb-1" />
            <div className="bg-orb orb-2" />
            <div className="bg-orb orb-3" />

            <div className="container">
                {/* Header */}
                <header className="app-header">
                    <div className="logo">
                        <span className="logo-icon">🤖</span>
                        <span className="logo-text">CV<span className="logo-accent">AI</span></span>
                    </div>
                    <p className="app-subtitle">
                        Phân tích và phân loại ngành nghề CV bằng trí tuệ nhân tạo
                    </p>
                </header>

                {/* Main Content */}
                <main className="main-content">
                    <div className="left-panel">
                        <div className="panel-title">
                            <span>📤</span> Tải lên CV của bạn
                        </div>
                        <UploadCV onResult={setResult} onLoading={setLoading} />
                    </div>

                    <div className="right-panel">
                        <div className="panel-title">
                            <span>📊</span> Kết quả phân tích
                        </div>
                        {loading ? (
                            <div className="loading-state">
                                <div className="spinner" />
                                <p>Đang phân tích CV...</p>
                            </div>
                        ) : result ? (
                            <Result data={result} />
                        ) : (
                            <div className="empty-state">
                                <span className="empty-icon">🔍</span>
                                <p>Kết quả sẽ hiển thị ở đây</p>
                                <p className="empty-sub">Upload CV và nhấn "Phân tích" để bắt đầu</p>
                            </div>
                        )}
                    </div>
                </main>

                {/* Footer */}
                <footer className="app-footer">
                    <p>CV AI Service · SVM + TF-IDF · 8 ngành nghề</p>
                </footer>
            </div>
        </div>
    );
}

export default App;
